func (q *Queries) ListProjects(ctx context.Context, arg ListProjectsParams) ([]ListProjectsRow, error) {
	rows, err := q.db.Query(ctx, listProjects,
		arg.TenantID,
		arg.Status,
		arg.DepartmentID,
		arg.BranchID,
		arg.ProjectManagerID,
		arg.Search,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ListProjectsRow
	for rows.Next() {
		var i ListProjectsRow
		if err := rows.Scan(
			&i.ID,
			&i.TenantID,
			&i.ProjectCode,
			&i.Name,
			&i.Description,
			&i.Status,
			&i.DepartmentID,
			&i.DepartmentName,
			&i.BranchID,
			&i.BranchName,
			&i.ProjectManagerID,
			&i.StartDate,
			&i.DueDate,
			&i.CompletedAt,
			&i.BudgetAmount,
			&i.CurrencyCode,
			&i.BillingType,
			&i.ClientLabel,
			&i.Priority,
			&i.Notes,
			&i.Metadata,
			&i.Inactive,
			&i.CreatedAt,
			&i.CreatedBy,
			&i.UpdatedAt,
			&i.UpdatedBy,
			&i.MilestoneCount,
			&i.SubmittedMilestoneCount,
			&i.AcceptedMilestoneCount,
			&i.RejectedMilestoneCount,
			&i.MilestoneAmount,
			&i.AcceptedAmount,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

